INSERT INTO quiz_question (id, word_bank_id, contextual_cloze, chinese_translation, correct_answer, distractor1, distractor2, distractor3, explanation_root_affix, explanation_mnemonic) VALUES
('243fc451-f564-597a-b86d-55452a85f3ce', '82f91108-38f0-4b1a-b73e-fbaacd6dc557', 'After a long day of studying, ___ often find myself thinking about my future career.', '在漫長的學習日後，我經常發現自己在思考我未來的職業。', 'I', 'You', 'We', 'They', 'I 是第一人稱單數主格代名詞。', 'I 就是「我」。'),
('246324b2-63c6-54c1-b186-c63555920b1a', '08d7bf36-48f0-4253-a22b-7357bfa6e2a1', 'A cup ___ hot tea was on the table.', '桌上有一杯熱茶。', 'of', 'in', 'for', 'by', '介係詞，用來表示內容或單位', 'a cup of... 表示「一杯...的...」'),
('b5ae09fc-84bf-5ae7-b8cf-7eb1b94bdb0a', '825a281c-8ba8-4992-9d3c-d724865fa454', '___ cat is very cute.', '那隻貓非常可愛。', 'That', 'Some', 'Each', 'Every', '形容詞，用來修飾名詞，指稱特定的對象。', '指向特定的對象。'),
('3f3748d7-9966-56c1-a87c-0bce0b029e0e', '4cb49395-91b8-403d-bb41-77e22ac4ae2f', 'I ___ go to school tomorrow.', '我明天將要去上學。', 'will', 'must', 'should', 'can', 'will 為單字，無詞根或詞綴。', 'will → 想到未來將會發生的事。'),
('fd9b16ff-f9cf-591f-a8e7-39c73dcc804a', '6f473860-59ac-4c93-809a-155f5d561a5f', 'Would you like to play ___ us after school?', '放學後你想跟我們一起玩嗎？', 'with', 'by', 'from', 'to', '表示「與...在一起」', '與某人在一起玩 → with');
